create type public.notification_delivery_status as enum('pending','processing','sent','failed','suppressed');create type public.support_status as enum('open','awaiting_staff','awaiting_customer','resolved','closed');create type public.support_priority as enum('low','normal','high','urgent');
create table public.notifications(id uuid primary key default gen_random_uuid(),profile_id uuid not null references public.profiles(id),event_type text not null,title text not null,body text not null,entity_type text,entity_id text,action_path text,dedupe_key text not null unique,read_at timestamptz,created_at timestamptz not null default now());
create table public.notification_deliveries(id uuid primary key default gen_random_uuid(),notification_id uuid not null references public.notifications(id),channel text not null check(channel in('in_app','email')),status public.notification_delivery_status not null default'pending',attempt_count int not null default 0,next_attempt_at timestamptz not null default now(),sent_at timestamptz,error_code text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(notification_id,channel));
create table public.support_tickets(id uuid primary key default gen_random_uuid(),account_id uuid not null references public.reward_accounts(id),submitted_by uuid not null references public.profiles(id),category text not null check(category in('rewards','benefits','credit','order','account','other')),subject text not null check(length(trim(subject))between 3 and 160),status public.support_status not null default'awaiting_staff',priority public.support_priority not null default'normal',assigned_to uuid references public.profiles(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),last_activity_at timestamptz not null default now());
create table public.support_messages(id uuid primary key default gen_random_uuid(),ticket_id uuid not null references public.support_tickets(id),author_profile_id uuid not null references public.profiles(id),body text not null check(length(trim(body))between 1 and 5000),internal boolean not null default false,created_at timestamptz not null default now());
create index notifications_profile_idx on public.notifications(profile_id,created_at desc);create index deliveries_pending_idx on public.notification_deliveries(status,next_attempt_at)where channel='email';create index support_queue_idx on public.support_tickets(status,priority,last_activity_at desc);create index support_messages_ticket_idx on public.support_messages(ticket_id,created_at);
create trigger notification_delivery_updated before update on public.notification_deliveries for each row execute function public.set_updated_at();create trigger support_ticket_updated before update on public.support_tickets for each row execute function public.set_updated_at();create trigger support_messages_immutable before update or delete on public.support_messages for each row execute function public.prevent_immutable_mutation();
alter table public.notifications enable row level security;alter table public.notification_deliveries enable row level security;alter table public.support_tickets enable row level security;alter table public.support_messages enable row level security;
create policy notification_own_read on public.notifications for select to authenticated using(profile_id=auth.uid());create policy delivery_staff_read on public.notification_deliveries for select to authenticated using(public.is_staff());create policy ticket_account_read on public.support_tickets for select to authenticated using(public.can_access_account(account_id)or public.is_staff());create policy message_visible_read on public.support_messages for select to authenticated using(exists(select 1 from public.support_tickets t where t.id=ticket_id and(public.is_staff()or(public.can_access_account(t.account_id)and not internal))));grant select on public.notifications,public.support_tickets,public.support_messages to authenticated;grant select on public.notification_deliveries to authenticated;revoke all on public.notifications,public.notification_deliveries,public.support_tickets,public.support_messages from anon;
create or replace function public.enqueue_notification(p_profile uuid,p_event text,p_title text,p_body text,p_entity_type text,p_entity_id text,p_action_path text,p_dedupe text)returns uuid language plpgsql security definer set search_path=public as $$declare n uuid;begin insert into public.notifications(profile_id,event_type,title,body,entity_type,entity_id,action_path,dedupe_key)values(p_profile,p_event,p_title,p_body,p_entity_type,p_entity_id,p_action_path,p_dedupe)on conflict(dedupe_key)do update set dedupe_key=excluded.dedupe_key returning id into n;insert into public.notification_deliveries(notification_id,channel,status)values(n,'in_app','sent'),(n,'email','pending')on conflict(notification_id,channel)do nothing;return n;end$$;revoke execute on function public.enqueue_notification(uuid,text,text,text,text,text,text,text)from public,anon,authenticated;
create or replace function public.notify_staff(p_event text,p_title text,p_body text,p_entity_type text,p_entity_id text,p_action_path text,p_dedupe text)returns void language plpgsql security definer set search_path=public as $$declare p record;begin for p in select id from public.profiles where role in('staff','admin')loop perform public.enqueue_notification(p.id,p_event,p_title,p_body,p_entity_type,p_entity_id,p_action_path,p_dedupe||':'||p.id);end loop;end$$;revoke execute on function public.notify_staff(text,text,text,text,text,text,text)from public,anon,authenticated;
create or replace function public.redemption_notification_trigger()returns trigger language plpgsql security definer set search_path=public as $$begin if tg_op='INSERT'then perform public.enqueue_notification(new.submitted_by,'redemption_submitted','Request received','Your '||new.kind||' request is awaiting staff review.','redemption_request',new.id::text,'/#requests','redemption:submitted:'||new.id);perform public.notify_staff('redemption_submitted','New redemption request','A customer submitted a '||new.kind||' request.','redemption_request',new.id::text,'/admin/','staff:redemption:'||new.id);elsif new.status is distinct from old.status then perform public.enqueue_notification(new.submitted_by,'redemption_'||new.status,'Request '||replace(new.status::text,'_',' '),'Your '||new.kind||' request is now '||replace(new.status::text,'_',' ')||'.','redemption_request',new.id::text,'/#requests','redemption:'||new.status||':'||new.id);end if;return new;end$$;create trigger redemption_notifications after insert or update of status on public.redemption_requests for each row execute function public.redemption_notification_trigger();
create or replace function public.mark_notification_read(p_id uuid)returns void language sql security definer set search_path=public as $$update public.notifications set read_at=coalesce(read_at,now())where id=p_id and profile_id=auth.uid()$$;create or replace function public.mark_all_notifications_read()returns void language sql security definer set search_path=public as $$update public.notifications set read_at=coalesce(read_at,now())where profile_id=auth.uid()$$;revoke execute on function public.mark_notification_read(uuid),public.mark_all_notifications_read()from public,anon;grant execute on function public.mark_notification_read(uuid),public.mark_all_notifications_read()to authenticated;
create or replace function public.create_support_ticket(p_account uuid,p_category text,p_subject text,p_message text)returns uuid language plpgsql security definer set search_path=public as $$declare t uuid;begin if not public.can_access_account(p_account)then raise exception'Account access denied';end if;insert into public.support_tickets(account_id,submitted_by,category,subject)values(p_account,auth.uid(),p_category,trim(p_subject))returning id into t;insert into public.support_messages(ticket_id,author_profile_id,body)values(t,auth.uid(),trim(p_message));perform public.enqueue_notification(auth.uid(),'support_created','Support request received','Onward has received “'||trim(p_subject)||'”.','support_ticket',t::text,'/#support','support:created:'||t);perform public.notify_staff('support_created','New support ticket',trim(p_subject),'support_ticket',t::text,'/admin/','staff:support:'||t);insert into public.audit_events(actor_profile_id,event_type,entity_type,entity_id)values(auth.uid(),'support_created','support_ticket',t::text);return t;end$$;
create or replace function public.reply_support_ticket(p_ticket uuid,p_body text)returns uuid language plpgsql security definer set search_path=public as $$declare m uuid;t public.support_tickets%rowtype;begin select*into t from public.support_tickets where id=p_ticket for update;if not found or(not public.can_access_account(t.account_id)and not public.is_staff())then raise exception'Ticket access denied';end if;insert into public.support_messages(ticket_id,author_profile_id,body,internal)values(p_ticket,auth.uid(),trim(p_body),false)returning id into m;if public.is_staff()then update public.support_tickets set status='awaiting_customer',last_activity_at=now()where id=p_ticket;perform public.enqueue_notification(t.submitted_by,'support_reply','Onward replied to your request',t.subject,'support_ticket',p_ticket::text,'/#support','support:reply:'||m);else update public.support_tickets set status='awaiting_staff',last_activity_at=now()where id=p_ticket;perform public.notify_staff('support_reply','Customer replied',t.subject,'support_ticket',p_ticket::text,'/admin/','staff:support:reply:'||m);end if;insert into public.audit_events(actor_profile_id,event_type,entity_type,entity_id)values(auth.uid(),'support_replied','support_ticket',p_ticket::text);return m;end$$;
create or replace function public.update_support_ticket(p_ticket uuid,p_status public.support_status,p_priority public.support_priority,p_assigned uuid,p_note text default null,p_internal boolean default true)returns void language plpgsql security definer set search_path=public as $$declare t public.support_tickets%rowtype;m uuid;begin if not public.is_staff()then raise exception'Staff access required';end if;select*into t from public.support_tickets where id=p_ticket for update;if not found then raise exception'Ticket not found';end if;update public.support_tickets set status=p_status,priority=p_priority,assigned_to=p_assigned,last_activity_at=now()where id=p_ticket;if nullif(trim(p_note),'')is not null then insert into public.support_messages(ticket_id,author_profile_id,body,internal)values(p_ticket,auth.uid(),trim(p_note),p_internal)returning id into m;if not p_internal then perform public.enqueue_notification(t.submitted_by,'support_reply','Onward updated your support request',t.subject,'support_ticket',p_ticket::text,'/#support','support:update:'||m);end if;end if;perform public.enqueue_notification(t.submitted_by,'support_'||p_status,'Support request '||replace(p_status::text,'_',' '),t.subject,'support_ticket',p_ticket::text,'/#support','support:status:'||p_status||':'||p_ticket);insert into public.audit_events(actor_profile_id,event_type,entity_type,entity_id,details)values(auth.uid(),'support_updated','support_ticket',p_ticket::text,jsonb_build_object('status',p_status,'priority',p_priority));end$$;
revoke execute on function public.create_support_ticket(uuid,text,text,text),public.reply_support_ticket(uuid,text),public.update_support_ticket(uuid,public.support_status,public.support_priority,uuid,text,boolean)from public,anon;grant execute on function public.create_support_ticket(uuid,text,text,text),public.reply_support_ticket(uuid,text),public.update_support_ticket(uuid,public.support_status,public.support_priority,uuid,text,boolean)to authenticated;
